        <label for="email">Email Address</label>
      </div>
      <button type="submit" id="submit-btn"><span>Send Me the Free Guide →</span></button>
      <p id="form-error" class="form-error" role="alert"></p>
    </form>

    <div id="form-success" class="form-success" role="status" aria-live="polite">
      <div class="success-badge">
        <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <path d="M5 12.5l4.5 4.5L19 7.5" />
        </svg>
      </div>
      <h2 class="success-title">Check your inbox</h2>
      <p class="success-subtext">The guide is on its way to <span id="success-email" class="success-email-pill">your email</span>. If you don't see it in a few minutes, check your spam folder.</p>
    </div>

    <p class="privacy">
      No spam<span class="privacy-dot"></span>Unsubscribe anytime<span class="privacy-dot"></span>Your email stays private
    </p>
  </section>

</main>

<script>
  (function () {
    var KLAVIYO_COMPANY_ID = 'WC5skj';
    var KLAVIYO_LIST_ID = 'YwuwRU';
    var KLAVIYO_ENDPOINT = 'https://a.klaviyo.com/client/subscriptions/?company_id=' + KLAVIYO_COMPANY_ID;

    var form = document.getElementById('optin-form');
    var firstNameInput = document.getElementById('firstname');
    var emailInput = document.getElementById('email');
    var button = document.getElementById('submit-btn');
    var buttonSpan = button.querySelector('span');
    var errorEl = document.getElementById('form-error');
    var successEl = document.getElementById('form-success');
    var successEmailEl = document.getElementById('success-email');
    var formLabelEl = document.getElementById('form-label');

    function isValidEmail(value) {
      return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
    }

    function showError(message) {
      errorEl.textContent = message;
      errorEl.classList.add('visible');
    }

    function clearError() {
      errorEl.textContent = '';
      errorEl.classList.remove('visible');
    }

    function lockForm() {
      firstNameInput.disabled = true;
      emailInput.disabled = true;
      button.disabled = true;
    }

    function showSuccess(email) {
      if (successEmailEl) successEmailEl.textContent = email;
      if (form) form.style.display = 'none';
      if (formLabelEl) formLabelEl.style.display = 'none';
      if (successEl) successEl.classList.add('visible');
    }

    form.addEventListener('submit', async function (event) {
      event.preventDefault();
      clearError();

      var email = emailInput.value.trim();
      var firstName = firstNameInput.value.trim();

      if (!email || !isValidEmail(email)) {
        showError('Please enter a valid email address.');
        emailInput.focus();
        return;
      }

      // Optimistic UI while the request is in flight
      var originalText = buttonSpan.textContent;
      button.disabled = true;
      buttonSpan.textContent = 'Sending…';

      var payload = {
        data: {
          type: 'subscription',
          attributes: {
            custom_source: 'Connor 90-Day Landing Page',
            profile: {
              data: {
                type: 'profile',
                attributes: {
                  email: email,
                  first_name: firstName || undefined
                }
              }
            }
          },
          relationships: {
            list: {
              data: {
                type: 'list',
                id: KLAVIYO_LIST_ID
              }
            }
          }
        }
      };

      try {
        var response = await fetch(KLAVIYO_ENDPOINT, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'revision': '2023-12-15'
          },
          body: JSON.stringify(payload)
        });

        // Klaviyo returns 202 Accepted on success with an empty body
        if (response.ok || response.status === 202) {
          showSuccess(email);
          return;
        }

        throw new Error('Request failed with status ' + response.status);
      } catch (err) {
        buttonSpan.textContent = originalText;
        button.disabled = false;
        showError('Something went wrong — please try again.');
      }
    });
  })();
</script>

<?php wp_footer(); ?>
